function CostumerReview ({scaleValue, reviewType}) {
    const range = [1, 2, 3, 4, 5]
    const scaleType = reviewType === 'confort' ?'😌': '💖'     // Cœur / Sourire relaxé
    return (
        <div>
            <div>
			{range.map((rangeElem) =>
				scaleValue >= rangeElem ? (
					<span key={rangeElem.toString()}>{scaleType}</span>
				) : null
			)}
		</div>
        </div>
    )

}

export default CostumerReview;
